private static boolean isIntegral(JsonPrimitive primitive) {
  if (primitive.value instanceof Number) {
    Number number = (Number) primitive.value;
    return number instanceof BigInteger
        || number instanceof Long
        || number instanceof Integer
        || number instanceof Short
        || number instanceof Byte;
  }
  return false;
}

public Excluder withExclusionStrategy(
    ExclusionStrategy exclusionStrategy, boolean serialization, boolean deserialization) {
  Excluder result = clone();
  if (serialization) {
    result.serializationStrategies = new ArrayList<>(serializationStrategies);
    result.serializationStrategies.add(exclusionStrategy);
  }
  if (deserialization) {
    result.deserializationStrategies = new ArrayList<>(deserializationStrategies);
    result.deserializationStrategies.add(exclusionStrategy);
  }
  return result;
}

public static int hashCodeMulti(final Object... objects) {
    int hash = 1;
    if (objects != null) {
        for (final Object object : objects) {
            final int tmpHash = Objects.hashCode(object);
            hash = hash * 31 + tmpHash;
        }
    }
    return hash;
}

public static String readStackTrace(Throwable throwable) {
	Preconditions.notNull(throwable, "Throwable must not be null");
	StringWriter stringWriter = new StringWriter();
	try (PrintWriter printWriter = new PrintWriter(stringWriter)) {
		throwable.printStackTrace(printWriter);
	}
	return stringWriter.toString();
}

private fun awaitTcpConnect(
  timeout: Long,
  unit: TimeUnit,
): ConnectResult? {
  if (tcpConnectsInFlight.isEmpty()) return null

  val result = connectResults.poll(timeout, unit) ?: return null

  tcpConnectsInFlight.remove(result.plan)

  return result
}
